UPDATE `petlog`.`feed`
SET like_count = like_count + 1
WHERE id = #{feedId}

UPDATE `petlog`.`feed`
SET like_count = IF(like_count > 0, like_count - 1, 0)
WHERE id = #{feedId}

UPDATE `petlog`.`feed`
SET comment_count = comment_count + #{count}
WHERE id = #{feedId}

mapper.select:
SELECT
`t1`.`id`                 AS feedId,
`t1`.`user_id`            AS userId,
`t2`.`nickname`           AS nickname,
`t3`.`image_url`          AS profileImageUrl,
`t4`.`address_primary`    AS address,
`t1`.`title`              AS title,
`t1`.`content`            AS content,
`t1`.`like_count`         AS likeCount,
`t1`.`comment_count`      AS commentCount,
`t1`.`created_at`         AS createdAt,
`t1`.`updated_at`         AS updatedAt
FROM `petlog`.`feed` `t1`
    JOIN `petlog`.`personal_user` `t2`
        ON `t2`.`user_id` = `t1`.`user_id`
    LEFT JOIN `petlog`.`pets` `t3`
        ON `t3`.`user_id` = `t1`.`user_id`
            AND `t3`.is_primary = 1
    LEFT JOIN `petlog`.`address` `t4`
        ON `t4`.`user_id` = `t1`.`user_id`

WHERE 1=1



    AND (
    `t2`.nickname LIKE CONCAT('%', #{keyword}, '%')
    OR `t1`.title LIKE CONCAT('%', #{keyword}, '%')
    )







            AND (`t1`.`created_at` < #{lastCreatedAt}
                OR (`t1`.`created_at` = #{lastCreatedAt}
                        AND `t1`.`id` < #{lastFeedId}
                    )
                )



            AND (`t1`.`like_count` < #{lastLikeCount}
                OR (`t1`.`like_count` = #{lastLikeCount}
                    AND `t1`.`id` < #{lastFeedId}
                )
            )






        ORDER BY `t1`.like_count DESC, `t1`.`id` DESC


        ORDER BY `t1`.`created_at` DESC, `t1`.`id` DESC


LIMIT #{size}
